#include <string.h>

char *dup_local(const char *src, size_t n) {
	char *buf = (char *)alloca(n + 1);
	memcpy(buf, src, n);
	buf[n] = '\0';
	return buf;
}

#include <stdlib.h>
#include <string.h>

#define MAX_LOCAL 4096

char *dup_local(const char *src, size_t n) {
	if (n + 1 > MAX_LOCAL) {
		return NULL;
	}
	char *buf = (char *)malloc(n + 1);
	if (buf == NULL) {
		return NULL;
	}
	memcpy(buf, src, n);
	buf[n] = '\0';
	return buf;
}
